const topics = [
  { topic: 'AI tools that save 10 hours per week', niche: 'productivity', cta: 'Book a free audit' },
  { topic: '5 signs your business needs automation now', niche: 'business growth', cta: 'DM us to learn more' },
  { topic: 'How AI is changing customer support', niche: 'customer service', cta: 'See our case study' },
  { topic: 'ChatGPT vs Claude vs Gemini for your business', niche: 'AI comparison', cta: 'Get our free guide' },
  { topic: 'Real examples of AI ROI in small business', niche: 'ROI and results', cta: 'Talk to our team' }
];
const personas = [
  { name: 'TechGrowthPro', tone: 'professional and data-driven', audience: 'B2B decision makers' },
  { name: 'AISimplified', tone: 'friendly and educational', audience: 'small business owners' }
];
const dayIndex = new Date().getDay() - 1;
const todayTopic = topics[dayIndex % topics.length];
return personas.map(persona => ({ json: { ...todayTopic, ...persona } }));

const d = $json;
const prompt = [
  'You are a social media creator for persona ' + d.name + '.',
  'Tone: ' + d.tone + '. Audience: ' + d.audience + '.',
  'Create content about this topic: ' + d.topic + ' (niche: ' + d.niche + ').',
  'CTA to use: ' + d.cta,
  '',
  'Respond ONLY with valid JSON in this exact format with no extra text:',
  '{"twitter":{"post":"max 280 chars with 2-3 hashtags","image_prompt":"visual prompt"},"linkedin":{"post":"150-200 words with 3-5 hashtags","image_prompt":"banner prompt"},"instagram":{"caption":"100-150 words with 10 hashtags at end","image_prompt":"square image prompt","story_text":"3 bullet points"}}'
].join('\n');

const requestBody = JSON.stringify({
  model: 'claude-opus-4-5',
  max_tokens: 1200,
  messages: [{ role: 'user', content: prompt }]
});

return [{ json: { ...d, requestBody } }];

const raw = $input.item.json.content[0].text.trim();

function extractFirstJson(str) {
  let depth = 0, inString = false, escape = false, start = -1;
  for (let i = 0; i < str.length; i++) {
    const ch = str[i];
    if (start === -1 && ch === '{') { start = i; }
    if (start === -1) continue;
    if (escape) { escape = false; continue; }
    if (ch === '\\' && inString) { escape = true; continue; }
    if (ch === '"') { inString = !inString; continue; }
    if (!inString) {
      if (ch === '{') depth++;
      else if (ch === '}') { depth--; if (depth === 0) return str.substring(start, i + 1); }
    }
  }
  return null;
}

const flat = raw.replace(/\r?\n/g, ' ');
const jsonStr = extractFirstJson(flat);
if (!jsonStr) throw new Error('No JSON found: ' + raw.substring(0, 150));

const content = JSON.parse(jsonStr);
const persona = $('Load Topic and Personas').item.json;

return [{
  json: {
    persona: persona.name,
    topic: persona.topic,
    generated_at: new Date().toISOString(),
    twitter: content.twitter,
    linkedin: content.linkedin,
    instagram: content.instagram,
    image_prompts: {
      twitter: content.twitter ? content.twitter.image_prompt : '',
      linkedin: content.linkedin ? content.linkedin.image_prompt : '',
      instagram: content.instagram ? content.instagram.image_prompt : ''
    }
  }
}];

const d = $json;
const twitterPost = d.twitter ? d.twitter.post : '';
const linkedinPost = d.linkedin ? d.linkedin.post : '';

const reviewPrompt = [
  'Review this social media content for quality and brand safety.',
  'Check: grammar, appropriate tone, no controversial claims, CTA is clear.',
  '',
  'Twitter: ' + twitterPost,
  'LinkedIn: ' + linkedinPost,
  '',
  'Respond ONLY with valid JSON: {"approved":true,"issues":[],"overall_score":8}'
].join('\n');

const requestBody = JSON.stringify({
  model: 'claude-opus-4-5',
  max_tokens: 300,
  messages: [{ role: 'user', content: reviewPrompt }]
});

return [{ json: { ...d, requestBody } }];

