const flat = raw.replace(/\r?\n/g, ' ');
const jsonStr = extractFirstJson(flat);
const review = JSON.parse(jsonStr);
const content = $('Parse Content').item.json;

return [{
  json: {
    ...content,
    review_approved: review.approved,
    review_score: review.overall_score,
    review_issues: review.issues || [],
    status: review.approved ? 'READY_TO_POST' : 'NEEDS_REVIEW'
  }
}];

console.log('APPROVED — Persona:', $json.persona);
console.log('Twitter:', $json.twitter ? $json.twitter.post : 'N/A');
console.log('LinkedIn:', $json.linkedin ? $json.linkedin.post.substring(0, 100) + '...' : 'N/A');
console.log('Score:', $json.review_score + '/10');
console.log('Status: READY TO POST — connect Buffer/Hootsuite/Airtable here');
return [{ json: { ...$json, action: 'READY_TO_POST' } }];
